"use client"

import { SweepWalletUi, type SweepWalletUiProps } from "./sweep-wallet-ui"
import {
  useSweepWallet,
  type ScanResult,
  type SweepResult,
  type UseSweepWalletOptions,
  type UseSweepWalletReturn,
} from "./use-sweep-wallet"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export { SweepWalletUi, type SweepWalletUiProps } from "./sweep-wallet-ui"
export {
  useSweepWallet,
  type ScanResult,
  type SweepResult,
  type SweepStep,
  type SweepFundingUtxo,
  type SweepOrdinalUtxo,
  type SweepTokenGroup,
  type UseSweepWalletOptions,
  type UseSweepWalletReturn,
} from "./use-sweep-wallet"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Props for the composed SweepWallet block */
export interface SweepWalletProps {
  /** Scan a WIF for spendable assets */
  onScan: (wif: string) => Promise<ScanResult>
  /** Execute the sweep transaction */
  onSweep: (wif: string, assets: ScanResult) => Promise<SweepResult>
  /** Callback after a successful sweep */
  onSuccess?: (result: SweepResult) => void
  /** Callback on any error */
  onError?: (error: Error) => void
  /** Optional CSS class */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Full sweep-wallet block: WIF input, scan, preview, sweep, and success/error states.
 *
 * Wires `useSweepWallet` (logic) into `SweepWalletUi` (presentation).
 * The caller provides `onScan` and `onSweep` callbacks that integrate with
 * `@1sat/actions` sweep utilities.
 *
 * @example
 * ```tsx
 * import { SweepWallet } from "@/components/blocks/sweep-wallet"
 *
 * <SweepWallet
 *   onScan={async (wif) => {
 *     const pk = PrivateKey.fromWif(wif)
 *     const address = pk.toPublicKey().toAddress()
 *     return await scanAddressUtxos(services, address)
 *   }}
 *   onSweep={async (wif, assets) => {
 *     const inputs = await prepareSweepInputs(ctx, assets.funding)
 *     return await sweepBsv.execute(ctx, { inputs, wif })
 *   }}
 * />
 * ```
 */
export function SweepWallet({
  onScan,
  onSweep,
  onSuccess,
  onError,
  className,
}: SweepWalletProps) {
  const hook = useSweepWallet({ onScan, onSweep, onSuccess, onError })

  return (
    <SweepWalletUi
      step={hook.step}
      wifInput={hook.wifInput}
      onWifInputChange={hook.setWifInput}
      isWifValid={hook.isWifValid}
      scanResult={hook.scanResult}
      sweepResult={hook.sweepResult}
      error={hook.error}
      isLoading={hook.isLoading}
      onScan={hook.handleScan}
      onSweep={hook.handleSweep}
      onReset={hook.handleReset}
      className={className}
    />
  )
}

"use client"

import {
  AlertCircle,
  CheckCircle2,
  ClipboardPaste,
  Coins,
  ImageIcon,
  KeyRound,
  Loader2,
  RotateCcw,
  Search,
  Wallet,
} from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Separator } from "@/components/ui/separator"
import { Skeleton } from "@/components/ui/skeleton"
import { cn } from "@/lib/utils"
import type {
  ScanResult,
  SweepResult,
  SweepStep,
} from "./use-sweep-wallet"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface SweepWalletUiProps {
  /** Current workflow step */
  step: SweepStep
  /** Current WIF input value */
  wifInput: string
  /** Update the WIF input */
  onWifInputChange: (value: string) => void
  /** Whether the WIF looks valid */
  isWifValid: boolean
  /** Scanned assets */
  scanResult: ScanResult | null
  /** Sweep result */
  sweepResult: SweepResult | null
  /** Error message */
  error: string | null
  /** Whether an async operation is in flight */
  isLoading: boolean
  /** Initiate scan */
  onScan: () => void
  /** Initiate sweep */
  onSweep: () => void
  /** Reset to input step */
  onReset: () => void
  /** Optional CSS class */
  className?: string
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const SATS_PER_BSV = 100_000_000

function formatSats(sats: number): string {
  if (sats >= SATS_PER_BSV) {
    return `${(sats / SATS_PER_BSV).toFixed(8)} BSV`
  }
  return `${sats.toLocaleString()} sats`
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

function ScanningState() {
  return (
    <div className="flex flex-col items-center gap-4 py-6">
      <Loader2 className="size-8 animate-spin text-muted-foreground" />
      <div className="flex flex-col items-center gap-1">
        <p className="text-sm font-medium">Scanning for assets...</p>
        <p className="text-xs text-muted-foreground">
          Checking funding UTXOs, ordinals, and tokens
        </p>
      </div>
      <div className="flex w-full flex-col gap-2">
        <Skeleton className="h-4 w-full" />
        <Skeleton className="h-4 w-3/4" />
        <Skeleton className="h-4 w-1/2" />
      </div>
    </div>
  )
}

function AssetPreview({ scanResult }: { scanResult: ScanResult }) {
  const { funding, ordinals, tokens, totalSats } = scanResult
  const fundingCount = funding.length
  const ordinalCount = ordinals.length
  const tokenCount = tokens.length

  return (
    <div className="flex flex-col gap-3">
      <p className="text-sm font-medium">Found Assets</p>

      {/* Funding */}
      {fundingCount > 0 && (
        <div className="flex items-center justify-between rounded-md border bg-muted/50 px-3 py-2">
          <div className="flex items-center gap-2">
            <Wallet className="size-4 text-muted-foreground" aria-hidden="true" />
            <span className="text-sm">BSV</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium">{formatSats(totalSats)}</span>
            <Badge variant="secondary" className="text-xs">
              {fundingCount} UTXO{fundingCount !== 1 ? "s" : ""}
            </Badge>
          </div>
        </div>
      )}

      {/* Ordinals */}
      {ordinalCount > 0 && (
        <div className="flex items-center justify-between rounded-md border bg-muted/50 px-3 py-2">
          <div className="flex items-center gap-2">
            <ImageIcon className="size-4 text-muted-foreground" aria-hidden="true" />
            <span className="text-sm">Ordinals</span>
          </div>
          <Badge variant="secondary" className="text-xs">
            {ordinalCount} item{ordinalCount !== 1 ? "s" : ""}
          </Badge>
        </div>
      )}

      {/* Tokens */}
      {tokens.map((token) => (
        <div
          key={token.tokenId}
          className="flex items-center justify-between rounded-md border bg-muted/50 px-3 py-2"
        >
          <div className="flex items-center gap-2">
            <Coins className="size-4 text-muted-foreground" aria-hidden="true" />
            <span className="text-sm">{token.symbol ?? "Token"}</span>
          </div>
          <span className="text-sm font-medium font-mono">{token.amount}</span>
        </div>
      ))}

      {fundingCount === 0 && ordinalCount === 0 && tokenCount === 0 && (
        <p className="text-sm text-muted-foreground text-center py-4">
          No assets found
        </p>
      )}
    </div>
  )
}

function SweepingState() {
  return (
    <div className="flex flex-col items-center gap-4 py-6">
      <Loader2 className="size-8 animate-spin text-primary" />
      <div className="flex flex-col items-center gap-1">
        <p className="text-sm font-medium">Sweeping assets...</p>
        <p className="text-xs text-muted-foreground">
          Building and broadcasting transactions
        </p>
      </div>
    </div>
  )
}

function SuccessState({
  sweepResult,
  onReset,
}: {
  sweepResult: SweepResult
  onReset: () => void
}) {
  return (
    <div className="flex flex-col gap-4">
      <div className="flex items-start gap-3 rounded-md border border-primary/20 bg-primary/5 p-3">
        <CheckCircle2 className="mt-0.5 size-4 flex-shrink-0 text-primary" />
        <div className="min-w-0 flex flex-col gap-1">
          <p className="text-sm font-medium">Sweep complete</p>
          {sweepResult.txid && (
            <Badge
              variant="outline"
              className="max-w-full truncate text-xs font-mono"
            >
              {sweepResult.txid}
            </Badge>
          )}
        </div>
      </div>
      <Button variant="outline" className="w-full" onClick={onReset}>
        <RotateCcw aria-hidden="true" data-icon="inline-start" />
        Sweep Another Wallet
      </Button>
    </div>
  )
}

function ErrorState({
  error,
  onReset,
}: {
  error: string
  onReset: () => void
}) {
  return (
    <div className="flex flex-col gap-4">
      <div className="flex items-start gap-3 rounded-md border border-destructive/20 bg-destructive/5 p-3">
        <AlertCircle className="mt-0.5 size-4 flex-shrink-0 text-destructive" />
        <div className="flex flex-col gap-1">
          <p className="text-sm font-medium">Sweep failed</p>
          <p className="text-xs text-muted-foreground">{error}</p>
        </div>
      </div>
      <Button variant="outline" className="w-full" onClick={onReset}>
        <RotateCcw aria-hidden="true" data-icon="inline-start" />
        Try Again
      </Button>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Main UI
// ---------------------------------------------------------------------------

/**
 * Pure presentation component for the sweep-wallet block.
 *
 * Renders a Card with WIF input, scan/preview, sweep progress, and
 * success/error states. Never imports SDK packages.
 */
export function SweepWalletUi({
  step,
  wifInput,
  onWifInputChange,
  isWifValid,
  scanResult,
  sweepResult,
  error,
  isLoading,
  onScan,
  onSweep,
  onReset,
  className,
}: SweepWalletUiProps) {
  const handlePaste = async () => {
    if (typeof navigator !== "undefined" && navigator.clipboard) {
      try {
        const text = await navigator.clipboard.readText()
        onWifInputChange(text.trim())
      } catch {
        // Clipboard permission denied -- user can paste manually
      }
    }
  }

  return (
    <Card className={cn("w-full max-w-md", className)}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <KeyRound className="size-5" aria-hidden="true" />
          Sweep Wallet
        </CardTitle>
        <CardDescription>
          Import assets from a WIF private key into your connected wallet.
        </CardDescription>
      </CardHeader>

      <CardContent className="flex flex-col gap-4">
        {/* WIF input -- visible in input & preview steps */}
        {(step === "input" || step === "preview") && (
          <div className="flex flex-col gap-2">
            <Label htmlFor="sweep-wif-input">WIF Private Key</Label>
            <div className="flex items-center gap-2">
              <Input
                id="sweep-wif-input"
                type="password"
                placeholder="5HueCG... or K... or L..."
                value={wifInput}
                onChange={(e) => onWifInputChange(e.target.value)}
                disabled={isLoading || step === "preview"}
                className="flex-1 font-mono text-sm"
                autoComplete="off"
                spellCheck={false}
              />
              {step === "input" && (
                <Button
                  type="button"
                  variant="outline"
                  size="icon"
                  className="flex-shrink-0"
                  onClick={() => { void handlePaste() }}
                  disabled={isLoading}
                  aria-label="Paste from clipboard"
                >
                  <ClipboardPaste aria-hidden="true" data-icon="inline-start" />
                </Button>
              )}
            </div>
            {wifInput.length > 0 && !isWifValid && (
              <p className="text-xs text-destructive" role="alert">
                Invalid WIF format
              </p>
            )}
          </div>
        )}

        {/* Scanning skeleton */}
        {step === "scanning" && <ScanningState />}

        {/* Asset preview */}
        {step === "preview" && scanResult && (
          <>
            <Separator />
            <AssetPreview scanResult={scanResult} />
          </>
        )}

        {/* Sweeping progress */}
        {step === "sweeping" && <SweepingState />}

        {/* Success */}
        {step === "done" && sweepResult && (
          <SuccessState sweepResult={sweepResult} onReset={onReset} />
        )}

        {/* Error */}
        {step === "error" && error && (
          <ErrorState error={error} onReset={onReset} />
        )}
      </CardContent>

      {/* Footer actions for input & preview steps */}
      {(step === "input" || step === "preview") && (
        <CardFooter>
          {step === "input" && (
            <Button
              className="w-full"
              disabled={!isWifValid || isLoading}
              onClick={onScan}
              aria-busy={isLoading}
            >
              <Search aria-hidden="true" data-icon="inline-start" />
              Scan for Assets
            </Button>
          )}
          {step === "preview" && (
            <div className="flex w-full flex-col gap-2">
              <Button
                className="w-full"
                disabled={isLoading}
                onClick={onSweep}
                aria-busy={isLoading}
              >
                <Wallet aria-hidden="true" data-icon="inline-start" />
                Sweep All
              </Button>
              <Button
                variant="ghost"
                className="w-full"
                onClick={onReset}
                disabled={isLoading}
              >
                Cancel
              </Button>
            </div>
          )}
        </CardFooter>
      )}
    </Card>
  )
}

import { useCallback, useMemo, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** A funding UTXO found during scan */
export interface SweepFundingUtxo {
  /** Outpoint in txid_vout format */
  outpoint: string
  /** Satoshis held by this output */
  satoshis: number
}

/** An ordinal UTXO found during scan */
export interface SweepOrdinalUtxo {
  /** Outpoint in txid_vout format */
  outpoint: string
}

/** A group of BSV-21 token UTXOs */
export interface SweepTokenGroup {
  /** Token ID in txid_vout format */
  tokenId: string
  /** Human-readable symbol (e.g. "GOLD") */
  symbol?: string
  /** Total token amount as string (bigint serialization) */
  amount: string
}

/** Categorized assets discovered by scanning a WIF/address */
export interface ScanResult {
  /** Standard funding UTXOs */
  funding: SweepFundingUtxo[]
  /** 1Sat ordinal UTXOs */
  ordinals: SweepOrdinalUtxo[]
  /** BSV-21 token groups */
  tokens: SweepTokenGroup[]
  /** Total satoshis across all funding UTXOs */
  totalSats: number
}

/** Result from a sweep operation */
export interface SweepResult {
  /** Transaction ID on success */
  txid?: string
  /** Error message on failure */
  error?: string
}

/** Step in the sweep workflow */
export type SweepStep = "input" | "scanning" | "preview" | "sweeping" | "done" | "error"

/** Options for the useSweepWallet hook */
export interface UseSweepWalletOptions {
  /** Scan a WIF for spendable assets. Called with the raw WIF string. */
  onScan: (wif: string) => Promise<ScanResult>
  /** Execute the sweep transaction. Called with WIF and the scan result. */
  onSweep: (wif: string, assets: ScanResult) => Promise<SweepResult>
  /** Callback after a successful sweep */
  onSuccess?: (result: SweepResult) => void
  /** Callback on any error (scan or sweep) */
  onError?: (error: Error) => void
}

/** Return value of the useSweepWallet hook */
export interface UseSweepWalletReturn {
  /** Current step in the workflow */
  step: SweepStep
  /** Current WIF input value */
  wifInput: string
  /** Update the WIF input */
  setWifInput: (value: string) => void
  /** Whether the WIF input looks valid (base58check, 51-52 chars) */
  isWifValid: boolean
  /** Scanned assets (available after successful scan) */
  scanResult: ScanResult | null
  /** Sweep result (available after successful sweep) */
  sweepResult: SweepResult | null
  /** Current error message */
  error: string | null
  /** Whether any async operation is in flight */
  isLoading: boolean
  /** Initiate scanning */
  handleScan: () => Promise<void>
  /** Initiate sweeping */
  handleSweep: () => Promise<void>
  /** Reset back to input step */
  handleReset: () => void
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** WIF is base58check, typically 51 chars (uncompressed) or 52 chars (compressed) */
const WIF_PATTERN = /^[5KL][1-9A-HJ-NP-Za-km-z]{50,51}$/

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

/**
 * Manages the sweep-wallet workflow: WIF input -> scan -> preview -> sweep -> done.
 *
 * Pure logic hook. Does not import any UI or SDK packages. The caller provides
 * `onScan` and `onSweep` callbacks that wire into `@1sat/actions`.
 */
export function useSweepWallet({
  onScan,
  onSweep,
  onSuccess,
  onError,
}: UseSweepWalletOptions): UseSweepWalletReturn {
  const [step, setStep] = useState<SweepStep>("input")
  const [wifInput, setWifInput] = useState("")
  const [scanResult, setScanResult] = useState<ScanResult | null>(null)
  const [sweepResult, setSweepResult] = useState<SweepResult | null>(null)
  const [error, setError] = useState<string | null>(null)

  const isWifValid = useMemo(() => WIF_PATTERN.test(wifInput.trim()), [wifInput])

  const isLoading = step === "scanning" || step === "sweeping"

  const handleScan = useCallback(async () => {
    const trimmed = wifInput.trim()
    if (!WIF_PATTERN.test(trimmed)) return

    setStep("scanning")
    setError(null)
    setScanResult(null)
    setSweepResult(null)

    try {
      const result = await onScan(trimmed)
      setScanResult(result)

      const hasAssets =
        result.funding.length > 0 ||
        result.ordinals.length > 0 ||
        result.tokens.length > 0

      if (hasAssets) {
        setStep("preview")
      } else {
        setError("No assets found for this key")
        setStep("error")
      }
    } catch (err) {
      const e = err instanceof Error ? err : new Error(String(err))
      setError(e.message)
      setStep("error")
      onError?.(e)
    }
  }, [wifInput, onScan, onError])

  const handleSweep = useCallback(async () => {
    if (!scanResult) return
    const trimmed = wifInput.trim()
    if (!WIF_PATTERN.test(trimmed)) return

    setStep("sweeping")
    setError(null)

    try {
      const result = await onSweep(trimmed, scanResult)

      if (result.error) {
        setError(result.error)
        setStep("error")
        onError?.(new Error(result.error))
      } else {
        setSweepResult(result)
        setStep("done")
        onSuccess?.(result)
      }
    } catch (err) {
      const e = err instanceof Error ? err : new Error(String(err))
      setError(e.message)
      setStep("error")
      onError?.(e)
    }
  }, [wifInput, scanResult, onSweep, onSuccess, onError])

  const handleReset = useCallback(() => {
    setStep("input")
    setWifInput("")
    setScanResult(null)
    setSweepResult(null)
    setError(null)
  }, [])

  return {
    step,
    wifInput,
    setWifInput,
    isWifValid,
    scanResult,
    sweepResult,
    error,
    isLoading,
    handleScan,
    handleSweep,
    handleReset,
  }
}
